/**
     * @template T
     *
     * @param list<T> $list
     *
     * @return T
     */
function last(array $list)
    {
        $count = count($list);

        if ($count === 0) {
            throw new \LogicException('The list may not be empty.');
        }

        return $list[$count - 1];
    }

